/* BTAspectRatio styles — Figma 820:3124.
   All colours/radii via @btech/tokens CSS vars — no hex fallbacks. */

/* ── Root container ─────────────────────────────────────────── */

.bt-aspect-ratio {
  position: relative;
  width: 100%;
  overflow: hidden;
  border-radius: var(--radius-md);
  background: var(--bg-secondary);
}

/* ── Ratio modifiers ────────────────────────────────────────── */

.bt-aspect-ratio--16-9 { aspect-ratio: 16 / 9; }
.bt-aspect-ratio--9-16 { aspect-ratio: 9 / 16; }
.bt-aspect-ratio--1-1  { aspect-ratio: 1 / 1;  }
.bt-aspect-ratio--4-5  { aspect-ratio: 4 / 5;  }
.bt-aspect-ratio--5-4  { aspect-ratio: 5 / 4;  }

/* ── Slot — fills the container absolutely ──────────────────── */

.bt-aspect-ratio__slot {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
}

/**
 * BTAspectRatio — layout utility atom (Figma 820:3124)
 *
 * Constrains its children to a fixed aspect ratio with overflow clipping.
 * Use as a wrapper for images, videos, maps, or any content that must
 * maintain a predictable proportion.
 *
 * @example
 * ```tsx
 * // 16:9 image (default)
 * <BTAspectRatio ratio="16:9">
 *   <img src="..." style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
 * </BTAspectRatio>
 *
 * // Square placeholder
 * <BTAspectRatio ratio="1:1" />
 *
 * // Portrait video
 * <BTAspectRatio ratio="9:16">
 *   <video src="..." style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
 * </BTAspectRatio>
 * ```
 */
import './BTAspectRatio.css';
import type { ReactNode } from 'react';
import type { BTAspectRatioProps, BTAspectRatioRatio } from './BTAspectRatio.types';

const RATIO_CLASS: Record<BTAspectRatioRatio, string> = {
  '16:9': 'bt-aspect-ratio--16-9',
  '9:16': 'bt-aspect-ratio--9-16',
  '1:1':  'bt-aspect-ratio--1-1',
  '4:5':  'bt-aspect-ratio--4-5',
  '5:4':  'bt-aspect-ratio--5-4',
};

export function BTAspectRatio({
  ratio = '16:9',
  className,
  children,
}: BTAspectRatioProps & { children?: ReactNode }) {
  const rootClass = ['bt-aspect-ratio', RATIO_CLASS[ratio], className]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={rootClass}>
      <div className="bt-aspect-ratio__slot">{children}</div>
    </div>
  );
}

BTAspectRatio.displayName = 'BTAspectRatio';

// BTAspectRatio types — Figma source: node 820:3124.

/**
 * Supported aspect ratios.
 * Maps to standard media / photography proportions.
 */
export type BTAspectRatioRatio = '16:9' | '9:16' | '1:1' | '4:5' | '5:4';

export interface BTAspectRatioProps {
  /**
   * Aspect ratio constraint applied to the container.
   * @default '16:9'
   */
  ratio?: BTAspectRatioRatio;
  /** Additional CSS class names. */
  className?: string;
}
